// Zbierz dane ze wszystkich źródeł
const items = $input.all();

// FB Insights
let insights = {};
try {
  const fbData = items[0]?.json?.data || [];
  for (const m of fbData) {
    const val = m.values?.[m.values.length - 1]?.value || 0;
    insights[m.name] = val;
  }
} catch(e) {}

// Messenger Log — policz wiadomości z ostatniego miesiąca
const messengerItems = items.filter(i => i.json.pytanie).map(i => i.json);
const monthAgo = new Date(Date.now() - 30*24*60*60*1000);
const recentMessages = messengerItems.filter(m => {
  try { return new Date(m.timestamp) >= monthAgo; } catch(e) { return false; }
});
const autoAnswered = recentMessages.filter(m => m.eskalacja !== 'true' && m.eskalacja !== true);

// Archiwum Postów
const archiveItems = items.filter(i => i.json.post_id).map(i => i.json);
const recentPosts = archiveItems.filter(p => {
  try { return new Date(p.data_archiwizacji) >= monthAgo; } catch(e) { return false; }
});
const totalEngagement = recentPosts.reduce((s, p) => s + (p.engagement || 0), 0);

// Kryzysy
const crisisItems = items.filter(i => i.json.typ && i.json.lokalizacja).map(i => i.json);
const recentCrisis = crisisItems.filter(c => {
  try { return new Date(c.data) >= monthAgo; } catch(e) { return false; }
});

const now = new Date();
const monthName = now.toLocaleDateString('pl-PL', { month: 'long', year: 'numeric' });

return [{
  json: {
    miesiac: monthName,
    // Social media
    zasieg: insights.page_impressions || 0,
    zaangazowani: insights.page_engaged_users || 0,
    interakcje: insights.page_post_engagements || 0,
    nowi_fani: insights.page_fan_adds || 0,
    fani_lacznie: insights.page_fans || 0,
    // Content
    opublikowane_posty: recentPosts.length,
    laczny_engagement: totalEngagement,
    sredni_engagement: recentPosts.length > 0 ? Math.round(totalEngagement / recentPosts.length) : 0,
    // Messenger
    wiadomosci_messenger: recentMessages.length,
    auto_odpowiedzi: autoAnswered.length,
    procent_auto: recentMessages.length > 0 ? Math.round(autoAnswered.length / recentMessages.length * 100) : 0,
    // Kryzysy
    komunikaty_kryzysowe: recentCrisis.length,
    // Obliczone metryki
    mieszkancy_poinformowani: insights.page_impressions || 0,
    czas_zaoszczedzony_h: Math.round(
      (recentPosts.length * 0.5) +      // 30 min/post zaoszczędzone
      (autoAnswered.length * 0.05) +     // 3 min/wiadomość zaoszczędzone
      (recentCrisis.length * 0.5) +      // 30 min/kryzys zaoszczędzone
      2                                    // raport miesięczny
    )
  }
}];

