const aiText = $json.candidates?.[0]?.content?.parts?.[0]?.text || '';
const data = $('Oblicz Wskazniki').first().json;

const fbMatch = aiText.match(/---FB---(.*?)---X---/s);
const xMatch = aiText.match(/---X---(.*?)$/s);

const post_fb = fbMatch ? fbMatch[1].trim() : aiText.substring(0, 600);
let tweet_x = xMatch ? xMatch[1].trim() : '';
if (tweet_x.length > 280) tweet_x = tweet_x.substring(0, 277) + '...';

return [{
  json: {
    ...data,
    post_fb,
    tweet_x,
    ai_full: aiText
  }
}];
